#include<bits/stdc++.h>
using namespace std;
struct segment_tree
{
    struct node
    {
        long long l,r,sum1,sum2,sum3;
        long long lson,rson;
        long long tag;
        node():tag(0){}
    }a[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        a[x].sum1=(a[a[x].lson].sum1+a[a[x].rson].sum1);
        a[x].sum2=(a[a[x].lson].sum2+a[a[x].rson].sum2);
        a[x].sum3=(a[a[x].lson].sum3+a[a[x].rson].sum3);
    }
    long long pfh(long long v)
    {
        return v*(v+1)*(v*2+1)/6;
    }
    void pushadd(long long x,long long v)
    {
        a[x].sum1+=(a[x].r-a[x].l+1)*v;
        a[x].sum2+=1ll*(a[x].l+a[x].r)*(a[x].r-a[x].l+1)/2*v;
        a[x].sum3+=(pfh(a[x].r)-pfh(a[x].l-1))*v;
        a[x].tag+=v;
    }
    void pushdown(long long x)
    {
        long long mid=(a[x].l+a[x].r)>>1;
        long long ls=a[x].lson,rs=a[x].rson;
        long long tg=a[x].tag;
        pushadd(ls,tg);
        pushadd(rs,tg);
        a[x].tag=0;
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt,mid=(l+r)>>1;
        a[x].l=l;
        a[x].r=r;
        if(l==r)
        {
            a[x].sum1=a[x].sum2=a[x].sum3=0;
            return x;
        }
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long l,long long r,long long z)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return;
        }
        if(l<=a[x].l&&a[x].r<=r)
        {
            pushadd(x,z);
            return;
        }
        pushdown(x);
        add(a[x].lson,l,r,z);
        add(a[x].rson,l,r,z);
        pushup(x);
    }
    long long getsum1(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum1;
        }
        pushdown(x);
        return (getsum1(a[x].lson,l,r)+getsum1(a[x].rson,l,r));
    }
    long long getsum2(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum2;
        }
        pushdown(x);
        return (getsum2(a[x].lson,l,r)+getsum2(a[x].rson,l,r));
    }
    long long getsum3(long long x,long long l,long long r)
    {
        if(a[x].l>r||a[x].r<l)
        {
            return 0;
        }
        if(a[x].l>=l&&a[x].r<=r)
        {
            return a[x].sum3;
        }
        pushdown(x);
        return (getsum3(a[x].lson,l,r)+getsum3(a[x].rson,l,r));
    }
}t;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    t.init(1,n);
    while(m--)
    {
        char op;
        long long l,r,v;
        cin>>op;
        scanf("%lld%lld",&l,&r);
        if(op=='C')
        {
            r--;
            scanf("%lld",&v);
            t.add(1,l,r,v);
        }
        else
        {
            r--;
            long long sum1=t.getsum1(1,l,r);
            long long sum2=t.getsum2(1,l,r);
            long long sum3=t.getsum3(1,l,r);
            long long a=(r-l+1-r*l)*sum1+(l+r)*sum2-sum3;
            long long b=(r-l+2)*(r-l+1)/2;
            long long g=__gcd(a,b);
            a/=g;
            b/=g;
            printf("%lld/%lld\n",a,b);
        }
    }
    return 0;
}
